import{_ as e,o as l,c as d,a2 as a}from"./chunks/framework.Pywvta2k.js";const o=JSON.parse('{"title":"方证对应速查（《伤寒论》+《金匮要略》）","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/06-跨病证索引/09-方证对应（伤寒论）.md","filePath":"tcm-data/06-跨病证索引/09-方证对应（伤寒论）.md","lastUpdated":1781084559000}'),n={name:"tcm-data/06-跨病证索引/09-方证对应（伤寒论）.md"};function r(s,t,i,g,x,y){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="方证对应速查-《伤寒论》-《金匮要略》" tabindex="-1">方证对应速查（《伤寒论》+《金匮要略》） <a class="header-anchor" href="#方证对应速查-《伤寒论》-《金匮要略》" aria-label="Permalink to &quot;方证对应速查（《伤寒论》+《金匮要略》）&quot;">​</a></h1><blockquote><p>按症状→选方的&quot;方证对应&quot;体系 参考黄煌、倪海厦、胡希恕等经方家的经验</p></blockquote><hr><h2 id="一、发热" tabindex="-1">一、发热 <a class="header-anchor" href="#一、发热" aria-label="Permalink to &quot;一、发热&quot;">​</a></h2><h3 id="发热-恶寒" tabindex="-1">发热+恶寒 <a class="header-anchor" href="#发热-恶寒" aria-label="Permalink to &quot;发热+恶寒&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">症状特征</th><th style="text-align:left;">方证</th><th style="text-align:left;">关键鉴别点</th></tr></thead><tbody><tr><td style="text-align:left;">发热恶寒+有汗</td><td style="text-align:left;"><strong>桂枝汤</strong></td><td style="text-align:left;">脉浮缓，汗出恶风</td></tr><tr><td style="text-align:left;">发热恶寒+无汗</td><td style="text-align:left;"><strong>麻黄汤</strong></td><td style="text-align:left;">脉浮紧，身痛</td></tr><tr><td style="text-align:left;">发热恶寒+项背强</td><td style="text-align:left;"><strong>桂枝加葛根汤</strong></td><td style="text-align:left;">项背不舒</td></tr><tr><td style="text-align:left;">发热恶寒+烦躁</td><td style="text-align:left;"><strong>大青龙汤</strong></td><td style="text-align:left;">无汗烦躁，脉浮紧</td></tr><tr><td style="text-align:left;">发热恶寒+咳喘</td><td style="text-align:left;"><strong>小青龙汤</strong></td><td style="text-align:left;">咳喘痰稀，表寒内饮</td></tr></tbody></table><h3 id="发热-不恶寒" tabindex="-1">发热+不恶寒 <a class="header-anchor" href="#发热-不恶寒" aria-label="Permalink to &quot;发热+不恶寒&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">症状特征</th><th style="text-align:left;">方证</th><th style="text-align:left;">关键鉴别点</th></tr></thead><tbody><tr><td style="text-align:left;">发热汗出+大渴</td><td style="text-align:left;"><strong>白虎汤</strong></td><td style="text-align:left;">大热大渴大汗，脉洪大</td></tr><tr><td style="text-align:left;">发热+便秘</td><td style="text-align:left;"><strong>承气汤类</strong></td><td style="text-align:left;">腹满痛，便秘</td></tr><tr><td style="text-align:left;">发热+往来寒热</td><td style="text-align:left;"><strong>小柴胡汤</strong></td><td style="text-align:left;">口苦咽干目眩，胸胁苦满</td></tr><tr><td style="text-align:left;">发热+晨退暮甚</td><td style="text-align:left;"><strong>青蒿鳖甲汤</strong></td><td style="text-align:left;">温病后期</td></tr></tbody></table><hr><h2 id="二、汗出异常" tabindex="-1">二、汗出异常 <a class="header-anchor" href="#二、汗出异常" aria-label="Permalink to &quot;二、汗出异常&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">症状</th><th style="text-align:left;">方证</th><th style="text-align:left;">鉴别</th></tr></thead><tbody><tr><td style="text-align:left;">自汗（白天动则汗出）</td><td style="text-align:left;"><strong>桂枝汤/玉屏风散</strong></td><td style="text-align:left;">表虚</td></tr><tr><td style="text-align:left;">盗汗（晚上睡中汗出）</td><td style="text-align:left;"><strong>当归六黄汤/六味地黄丸</strong></td><td style="text-align:left;">阴虚</td></tr><tr><td style="text-align:left;">前胸出汗多+后背少（普光）</td><td style="text-align:left;"><strong>金鼎汤/温氏奔豚汤</strong></td><td style="text-align:left;">相火不降</td></tr><tr><td style="text-align:left;">但头汗出</td><td style="text-align:left;"><strong>茵陈蒿汤/柴胡汤</strong></td><td style="text-align:left;">湿热/郁热</td></tr><tr><td style="text-align:left;">手脚心汗出</td><td style="text-align:left;"><strong>桂枝汤加龙牡</strong></td><td style="text-align:left;">肝郁</td></tr></tbody></table><hr><h2 id="三、口渴" tabindex="-1">三、口渴 <a class="header-anchor" href="#三、口渴" aria-label="Permalink to &quot;三、口渴&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">症状</th><th style="text-align:left;">方证</th><th style="text-align:left;">鉴别</th></tr></thead><tbody><tr><td style="text-align:left;">大渴欲饮冷</td><td style="text-align:left;"><strong>白虎汤</strong></td><td style="text-align:left;">实热</td></tr><tr><td style="text-align:left;">口渴不欲饮</td><td style="text-align:left;"><strong>五苓散/苓桂术甘汤</strong></td><td style="text-align:left;">水饮内停</td></tr><tr><td style="text-align:left;">口渴+多饮不解（普光）</td><td style="text-align:left;"><strong>金鼎汤/潜阳丹</strong></td><td style="text-align:left;">相火不降</td></tr><tr><td style="text-align:left;">口渴+但欲漱水不欲咽</td><td style="text-align:left;"><strong>抵挡汤/血府逐瘀汤</strong></td><td style="text-align:left;">瘀血</td></tr><tr><td style="text-align:left;">口渴+小便不利</td><td style="text-align:left;"><strong>五苓散/猪苓汤</strong></td><td style="text-align:left;">水蓄</td></tr></tbody></table><hr><h2 id="四、咳嗽" tabindex="-1">四、咳嗽 <a class="header-anchor" href="#四、咳嗽" aria-label="Permalink to &quot;四、咳嗽&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">症状</th><th style="text-align:left;">方证</th></tr></thead><tbody><tr><td style="text-align:left;">咳+白稀痰+恶寒</td><td style="text-align:left;">小青龙汤</td></tr><tr><td style="text-align:left;">咳+黄痰+咽痛</td><td style="text-align:left;">麻杏石甘汤</td></tr><tr><td style="text-align:left;">咳+干咳无痰</td><td style="text-align:left;">麦门冬汤</td></tr><tr><td style="text-align:left;">咳+胸满</td><td style="text-align:left;">厚朴麻黄汤</td></tr><tr><td style="text-align:left;">咳+痰多清稀</td><td style="text-align:left;">苓甘五味姜辛汤</td></tr></tbody></table><hr><h2 id="五、头痛" tabindex="-1">五、头痛 <a class="header-anchor" href="#五、头痛" aria-label="Permalink to &quot;五、头痛&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">头痛部位</th><th style="text-align:left;">归经</th><th style="text-align:left;">方证</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>后头痛</strong>（项背）</td><td style="text-align:left;">太阳经</td><td style="text-align:left;">桂枝加葛根汤</td></tr><tr><td style="text-align:left;"><strong>前额痛</strong>（眉棱骨）</td><td style="text-align:left;">阳明经</td><td style="text-align:left;">葛根汤/白虎汤</td></tr><tr><td style="text-align:left;"><strong>偏头痛</strong>（两侧）</td><td style="text-align:left;">少阳经</td><td style="text-align:left;">小柴胡汤/川芎茶调散</td></tr><tr><td style="text-align:left;"><strong>巅顶痛</strong>（头顶）</td><td style="text-align:left;">厥阴经</td><td style="text-align:left;">吴茱萸汤</td></tr><tr><td style="text-align:left;"><strong>全头痛</strong>+沉重</td><td style="text-align:left;">太阴经/湿</td><td style="text-align:left;">羌活胜湿汤</td></tr></tbody></table><hr><h2 id="六、失眠" tabindex="-1">六、失眠 <a class="header-anchor" href="#六、失眠" aria-label="Permalink to &quot;六、失眠&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">症状</th><th style="text-align:left;">方证</th><th style="text-align:left;">鉴别</th></tr></thead><tbody><tr><td style="text-align:left;">虚烦不得眠</td><td style="text-align:left;"><strong>酸枣仁汤</strong></td><td style="text-align:left;">肝血虚</td></tr><tr><td style="text-align:left;">心烦失眠+手足热</td><td style="text-align:left;"><strong>黄连阿胶汤</strong></td><td style="text-align:left;">少阴热化</td></tr><tr><td style="text-align:left;">失眠+焦虑+易醒（普明）</td><td style="text-align:left;"><strong>温胆汤/酸枣仁汤</strong></td><td style="text-align:left;">胆虚痰扰</td></tr><tr><td style="text-align:left;">失眠+心悸</td><td style="text-align:left;"><strong>炙甘草汤</strong></td><td style="text-align:left;">气血两虚</td></tr><tr><td style="text-align:left;">失眠+胃中不和</td><td style="text-align:left;"><strong>半夏秫米汤</strong></td><td style="text-align:left;">胃不和则卧不安</td></tr></tbody></table><hr><h2 id="七、腹痛" tabindex="-1">七、腹痛 <a class="header-anchor" href="#七、腹痛" aria-label="Permalink to &quot;七、腹痛&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">部位</th><th style="text-align:left;">方证</th></tr></thead><tbody><tr><td style="text-align:left;">全腹痛+拒按+便秘</td><td style="text-align:left;">大承气汤</td></tr><tr><td style="text-align:left;">腹痛+喜温喜按</td><td style="text-align:left;">小建中汤/理中汤</td></tr><tr><td style="text-align:left;">胁下痛</td><td style="text-align:left;">小柴胡汤</td></tr><tr><td style="text-align:left;">少腹痛+（女性）</td><td style="text-align:left;">桂枝茯苓丸/当归芍药散</td></tr><tr><td style="text-align:left;">腹痛+腹中寒气</td><td style="text-align:left;">附子粳米汤</td></tr></tbody></table><hr><h2 id="八、月经病方证-普明相关" tabindex="-1">八、月经病方证（普明相关） <a class="header-anchor" href="#八、月经病方证-普明相关" aria-label="Permalink to &quot;八、月经病方证（普明相关）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">症状</th><th style="text-align:left;">方证</th></tr></thead><tbody><tr><td style="text-align:left;">月经先期+烦躁+乳房胀</td><td style="text-align:left;">丹栀逍遥散</td></tr><tr><td style="text-align:left;">月经先期+量少+（阴虚）</td><td style="text-align:left;">两地汤</td></tr><tr><td style="text-align:left;">月经先后不定期</td><td style="text-align:left;">定经汤（傅青主）</td></tr><tr><td style="text-align:left;">月经后期+怕冷+小腹痛</td><td style="text-align:left;">温经汤</td></tr><tr><td style="text-align:left;">痛经+血块+颜色暗</td><td style="text-align:left;">少腹逐瘀汤</td></tr></tbody></table><hr><h2 id="九、水肿-湿证" tabindex="-1">九、水肿/湿证 <a class="header-anchor" href="#九、水肿-湿证" aria-label="Permalink to &quot;九、水肿/湿证&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">症状</th><th style="text-align:left;">方证</th></tr></thead><tbody><tr><td style="text-align:left;">头面肿+怕风</td><td style="text-align:left;">越婢汤</td></tr><tr><td style="text-align:left;">全身肿+怕冷</td><td style="text-align:left;">真武汤</td></tr><tr><td style="text-align:left;">下肢肿+小便不利</td><td style="text-align:left;">五苓散</td></tr><tr><td style="text-align:left;">阴囊潮湿+脚气（普光）</td><td style="text-align:left;">二妙散/四妙散</td></tr></tbody></table><hr><h2 id="十、高血压方证对应" tabindex="-1">十、高血压方证对应 <a class="header-anchor" href="#十、高血压方证对应" aria-label="Permalink to &quot;十、高血压方证对应&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">证型</th><th style="text-align:left;">方证</th><th style="text-align:left;">适合普光？</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>水寒土湿、相火不降</strong></td><td style="text-align:left;"><strong>金鼎汤/温氏奔豚汤</strong></td><td style="text-align:left;">✅ <strong>最佳匹配</strong></td></tr><tr><td style="text-align:left;">肝阳上亢</td><td style="text-align:left;">镇肝熄风汤/天麻钩藤饮</td><td style="text-align:left;">⚠️ 不完全是</td></tr><tr><td style="text-align:left;">阴虚阳亢</td><td style="text-align:left;">大补阴丸</td><td style="text-align:left;">❌ 不适合</td></tr><tr><td style="text-align:left;">湿热上扰</td><td style="text-align:left;">黄连解毒汤</td><td style="text-align:left;">❌ 不适合</td></tr></tbody></table><hr><p><em>本索引为精简框架版。可按需继续扩展至&quot;金匮要略方证对应&quot;&quot;妇科方证&quot;&quot;儿科方证&quot;等专题。</em></p>',37)])])}const h=e(n,[["render",r]]);export{o as __pageData,h as default};
